// Document parser for dtapet.com article pipeline
const doc = $input.first().json;

let title = doc.title || 'Untitled';
let content = '';
let h1Found = false;

// Extract text content from document body
if (doc.body && doc.body.content) {
  for (const element of doc.body.content) {
    if (element.paragraph) {
      const para = element.paragraph;
      let paraText = '';

      for (const elem of (para.elements || [])) {
        if (elem.textRun) {
          paraText += elem.textRun.content;
        }
      }

      const style = para.paragraphStyle?.namedStyleType || 'NORMAL_TEXT';

      if (style === 'HEADING_1') {
        if (!h1Found) {
          title = paraText.trim();
          h1Found = true;
        }
      } else if (style === 'HEADING_2') {
        content += `<h2>${paraText.trim()}</h2>\n`;
      } else if (style === 'HEADING_3') {
        content += `<h3>${paraText.trim()}</h3>\n`;
      } else if (paraText.trim()) {
        content += `<p>${paraText.trim()}</p>\n`;
      }
    }
  }
}

// dtapet.com business configuration
const articleTopic = title;
const siteUrl = 'https://www.dtapet.com/';
const contactUrl = 'https://www.dtapet.com/%D7%99%D7%A6%D7%99%D7%A8%D7%AA-%D7%A7%D7%A9%D7%A8/';
const whatsappUrl = '';
const phoneNumber = '03-5235553';
const businessName = '\u05D3\u05D5\u05D9\u05D8\u05E9\u05DE\u05DF \u05D8\u05E4\u05D8\u05D9\u05DD';
const businessDescription = '\u05D7\u05E0\u05D5\u05EA \u05D8\u05E4\u05D8\u05D9\u05DD, \u05D5\u05D9\u05DC\u05D5\u05E0\u05D5\u05EA, \u05D7\u05D9\u05E4\u05D5\u05D9\u05D9\u05DD \u05E4\u05D5\u05DC\u05D9\u05DE\u05E8\u05D9\u05D9\u05DD \u05D5\u05E4\u05E8\u05E7\u05D8 SPC \u05D1\u05E4\u05EA\u05D7 \u05EA\u05E7\u05D5\u05D5\u05D4';
const authorImageUrl = 'https://www.dtapet.com/wp-content/uploads/2022/09/logo-e1663485891304.png';
const productsJson = '[]';

return {
  json: {
    title,
    content,
    docId: doc.documentId,
    docTitle: doc.title,
    articleTopic,
    siteUrl,
    contactUrl,
    whatsappUrl,
    phoneNumber,
    businessName,
    businessDescription,
    authorImageUrl,
    productsJson
  }
};

// WordPress preparation for dtapet.com
const improved = $input.first().json;
const original = $node['Parse Document'].json;

let htmlContent = improved.improved_html || improved.html || original.content;

// WordPress safety: strip any <style> blocks that may have leaked in
htmlContent = htmlContent.replace(/<style[\s\S]*?<\/style>/gi, '');

// WordPress safety: strip any class= attributes
htmlContent = htmlContent.replace(/\s*class="[^"]*"/g, '');

// WordPress safety: fix summary elements that use display:flex
htmlContent = htmlContent.replace(/(<summary[^>]*style="[^"]*?)display\s*:\s*flex(?:!important)?/gi, '$1display:block!important;position:relative!important');

// Strip date labels
htmlContent = htmlContent.replace(/<(?:span|p|div)[^>]*>\s*(?:\d{1,2}\s+(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{4}|\d{1,2}\/\d{1,2}\/\d{4})\s*<\/(?:span|p|div)>/gi, '');

// Strip Hebrew date labels
htmlContent = htmlContent.replace(/<(?:span|p|div)[^>]*>\s*(?:\u05E0\u05DB\u05EA\u05D1 \u05D1\u05EA\u05D0\u05E8\u05D9\u05DA|\u05E2\u05D5\u05D3\u05DB\u05DF \u05DC\u05D0\u05D7\u05E8\u05D5\u05E0\u05D4)[^<]*<\/(?:span|p|div)>/gi, '');

// Ensure article wrapper
if (!htmlContent.trim().startsWith('<article')) {
  htmlContent = '<article lang="he" dir="rtl">' + htmlContent + '</article>';
}

return {
  json: {
    title: original.title,
    content: htmlContent,
    excerpt: improved.meta_description || '',
    seoScore: improved.seo_score || 0,
    improvements: improved.improvements || [],
    docId: original.docId,
    status: 'draft'
  }
};

